export function initPaymentButtons(){document.querySelectorAll("a[data-plan]").forEach(e=>{e.addEventListener("click",o=>{o.preventDefault();const t=e.getAttribute("data-plan");if(t==="poutnik"){window.Auth?.isLoggedIn()?window.location.href="profil.html":window.Auth?.toggleModal?.();return}s(t,e)})})}async function s(a,e){if(!window.Auth||!window.Auth.isLoggedIn()){window.Auth?.showToast?.("P\u0159ihl\xE1\u0161en\xED vy\u017Eadov\xE1no","Pro n\xE1kup p\u0159edplatn\xE9ho se pros\xEDm nejd\u0159\xEDve p\u0159ihlaste.","info"),window.Auth?.toggleModal?.();return}const o=e.innerHTML;try{e.disabled=!0,e.style.opacity="0.7",e.innerHTML='<span class="loading-spinner" style="width: 16px; height: 16px; border-width: 2px; vertical-align: middle; margin-right: 8px;"></span> P\u0159esm\u011Brov\xE1n\xED...';const t=window.Auth.token||localStorage.getItem("auth_token"),l=window.API_CONFIG?.BASE_URL||"http://localhost:3001/api",n=await fetch(`${l}/payment/create-checkout-session`,{method:"POST",credentials:"include",headers:{"Content-Type":"application/json",Authorization:`Bearer ${t}`},body:JSON.stringify({planId:a})});if(!n.ok){let i="Nepoda\u0159ilo se vytvo\u0159it platebn\xED relaci";try{i=(await n.json()).error||i}catch{}throw new Error(i)}const r=await n.json();if(r.url)window.location.href=r.url;else throw new Error(r.error||"Nepoda\u0159ilo se vytvo\u0159it platebn\xED relaci")}catch(t){console.error("Payment Error:",t),window.Auth?.showToast?.("Chyba platby",t.message,"error"),e.disabled=!1,e.style.opacity="1",e.innerHTML=o}}
